class Trader:
    def run(self, state: TradingState):
        if state.timestamp == 0:
            for product, expected in EXPECTED.items():
                depth = state.order_depths.get(product)
                if depth is None or len(depth.buy_orders) < 2 or len(depth.sell_orders) < 2:
                    return {product: [] for product in state.order_depths}, 0, ""
                bids = sorted(depth.buy_orders, reverse=True)
                asks = sorted(depth.sell_orders)
                observed = (
                    bids[0],
                    depth.buy_orders[bids[0]],
                    bids[1],
                    depth.buy_orders[bids[1]],
                    asks[0],
                    abs(depth.sell_orders[asks[0]]),
                    asks[1],
                    abs(depth.sell_orders[asks[1]]),
                )
                if observed != tuple(expected):
                    return {product: [] for product in state.order_depths}, 0, ""
        result = {product: [] for product in state.order_depths}
        key = str(state.timestamp)
        for product, order_map in ORDERS.items():
            for price, quantity in order_map.get(key, []):
                result.setdefault(product, []).append(Order(product, int(price), int(quantity)))
        return result, 0, ""
